package com.back.capstone.service;
import com.back.capstone.dto.FileResponse; import com.back.capstone.entity.*; import com.back.capstone.exception.ApiException; import com.back.capstone.repository.FileMetadataRepository; import java.nio.file.*; import java.util.*; import org.springframework.beans.factory.annotation.Value; import org.springframework.http.HttpStatus; import org.springframework.security.core.Authentication; import org.springframework.stereotype.Service; import org.springframework.web.multipart.MultipartFile;
@Service public class FileService {private final FileMetadataRepository files;private final UserService users;private final Path root;public FileService(FileMetadataRepository f,UserService u,@Value("${file.upload-dir}") String dir){files=f;users=u;root=Paths.get(dir).toAbsolutePath().normalize();}
 public List<FileResponse> upload(Authentication a,List<MultipartFile> uploads){User u=users.current(a);return uploads.stream().map(x->store(u,x)).toList();} private FileResponse store(User u,MultipartFile x){if(x.isEmpty())throw new ApiException(HttpStatus.BAD_REQUEST,"Empty files cannot be uploaded.");try{Files.createDirectories(root.resolve("files"));String original=Paths.get(Objects.requireNonNullElse(x.getOriginalFilename(),"upload")).getFileName().toString();String ext=ext(original);String stored=UUID.randomUUID()+ext;Files.copy(x.getInputStream(),root.resolve("files").resolve(stored),StandardCopyOption.REPLACE_EXISTING);FileMetadata f=new FileMetadata();f.setOwner(u);f.setOriginalName(original);f.setStoredName(stored);f.setMimeType(Objects.requireNonNullElse(x.getContentType(),"application/octet-stream"));f.setExtension(ext);f.setSize(x.getSize());f.setCategory(f.getMimeType().startsWith("image/")?FileCategory.PHOTO:FileCategory.FILE);return response(files.save(f));}catch(ApiException e){throw e;}catch(Exception e){throw new ApiException(HttpStatus.INTERNAL_SERVER_ERROR,"Could not store uploaded file.");}}
 public List<FileResponse> list(Authentication a,String category){User u=users.current(a);if(category==null||category.isBlank())return files.findByOwnerOrderByUploadedAtDesc(u).stream().map(this::response).toList();try{return files.findByOwnerAndCategoryOrderByUploadedAtDesc(u,FileCategory.valueOf(category.toUpperCase())).stream().map(this::response).toList();}catch(IllegalArgumentException e){throw new ApiException(HttpStatus.BAD_REQUEST,"Invalid file category.");}}
 public List<FileResponse> recent(Authentication a){return files.findTop10ByOwnerOrderByUploadedAtDesc(users.current(a)).stream().map(this::response).toList();} public List<FileResponse> search(Authentication a,String q){return files.findByOwnerAndOriginalNameContainingIgnoreCaseOrderByUploadedAtDesc(users.current(a),q==null?"":q).stream().map(this::response).toList();}
 public FileMetadata owned(Authentication a,Long id){return files.findByIdAndOwner(id,users.current(a)).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,"File not found."));} public FileResponse get(Authentication a,Long id){return response(owned(a,id));} public Path content(Authentication a,Long id){FileMetadata f=owned(a,id);Path p=root.resolve("files").resolve(f.getStoredName()).normalize();if(!Files.exists(p))throw new ApiException(HttpStatus.NOT_FOUND,"Stored file is missing.");return p;} public void delete(Authentication a,Long id){FileMetadata f=owned(a,id);try{Files.deleteIfExists(root.resolve("files").resolve(f.getStoredName()));}catch(Exception e){throw new ApiException(HttpStatus.INTERNAL_SERVER_ERROR,"Could not remove stored file.");}files.delete(f);} private String ext(String n){int i=n.lastIndexOf('.');return i<0?"":n.substring(i).replaceAll("[^A-Za-z0-9.]","");} private FileResponse response(FileMetadata f){return new FileResponse(f.getId(),f.getOriginalName(),f.getMimeType(),f.getExtension(),f.getSize(),f.getCategory().name(),f.getUploadedAt(),"/files/"+f.getId()+"/content","/files/"+f.getId()+"/download");}}
